from functools import cache

@cache
def fib(n: int) -> int:
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)

# Without @cache: O(2^n) calls.  With @cache: O(n) calls, O(n) space.
print(fib(50))  # 12586269025 — instant

def merge_sort(arr: list[int]) -> list[int]:
    # Base case: a list of 0 or 1 elements is already sorted
    if len(arr) <= 1:
        return arr

    mid = len(arr) // 2
    left  = merge_sort(arr[:mid])   # recursive call on left half
    right = merge_sort(arr[mid:])   # recursive call on right half
    return merge(left, right)

def merge(left: list[int], right: list[int]) -> list[int]:
    result, i, j = [], 0, 0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i]); i += 1
        else:
            result.append(right[j]); j += 1
    return result + left[i:] + right[j:]

# Run
data = [38, 27, 43, 3, 9, 82, 10]
print(merge_sort(data))  # [3, 9, 10, 27, 38, 43, 82]

def flatten_json(
    obj: dict | list | object,
    prefix: str = "",
    sep: str = ".",
    max_depth: int = 20,
    _depth: int = 0,
) -> dict:
    """Recursively flatten nested dicts/lists into a single-level dict.

    >>> flatten_json({"a": {"b": 1, "c": [2, 3]}})
    {'a.b': 1, 'a.c.0': 2, 'a.c.1': 3}
    """
    if _depth > max_depth:
        return {prefix: obj}   # treat too-deep nodes as leaves

    out: dict = {}
    if isinstance(obj, dict):
        for key, val in obj.items():
            full_key = f"{prefix}{sep}{key}" if prefix else key
            out.update(flatten_json(val, full_key, sep, max_depth, _depth + 1))
    elif isinstance(obj, list):
        for idx, val in enumerate(obj):
            full_key = f"{prefix}{sep}{idx}" if prefix else str(idx)
            out.update(flatten_json(val, full_key, sep, max_depth, _depth + 1))
    else:
        out[prefix] = obj
    return out

# Run
nested = {"user": {"name": "Alice", "scores": [95, 87, 100]}, "active": True}
print(flatten_json(nested))
# {'user.name': 'Alice', 'user.scores.0': 95, 'user.scores.1': 87,
#  'user.scores.2': 100, 'active': True}

// Recursively decompose a task tree and collect all leaf actions.
// Each node is { title: string, children?: Node[] }.
function collectLeafActions(node, depth = 0, maxDepth = 6) {
  if (depth > maxDepth) {
    // Safety cap — treat this node as a leaf even if it has children
    return [{ action: "TRUNCATED", title: node.title }];
  }

  if (!node.children || node.children.length === 0) {
    // Base case: leaf node — this is an executable action
    return [{ action: "EXECUTE", title: node.title }];
  }

  // Recursive case: decompose each child and flatten results
  return node.children.flatMap(child =>
    collectLeafActions(child, depth + 1, maxDepth)
  );
}

