from pathlib import Path
from functools import cache
import ast, sys

MAX_DEPTH = 15

def build_symbol_index(
    root: Path,
    _depth: int = 0,
    _seen: set[str] | None = None,
) -> dict[str, Path]:
    """Return {symbol_name: defining_file} for all .py files under root."""
    if _seen is None:
        _seen = set()

    # Guard: depth cap and cycle detection via resolved path
    resolved = str(root.resolve())
    if _depth > MAX_DEPTH or resolved in _seen:
        return {}
    _seen.add(resolved)

    index: dict[str, Path] = {}

    for entry in root.iterdir():
        if entry.is_file() and entry.suffix == ".py":
            index.update(extract_symbols(entry))
        elif entry.is_dir() and not entry.name.startswith("."):
            # Recursive call — depth increments, shared _seen prevents cycles
            index.update(build_symbol_index(entry, _depth + 1, _seen))

    return index

@cache
def extract_symbols(path: Path) -> dict[str, Path]:
    """Parse a single .py file and return top-level name -> path pairs.
    Memoized so the same file is never parsed twice even if reachable
    from multiple directories.
    """
    try:
        tree = ast.parse(path.read_text(encoding="utf-8"))
    except (SyntaxError, UnicodeDecodeError):
        return {}

    symbols: dict[str, Path] = {}
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            symbols[node.name] = path
    return symbols

if __name__ == "__main__":
    idx = build_symbol_index(Path(sys.argv[1] if len(sys.argv) > 1 else "."))
    for name, filepath in sorted(idx.items())[:10]:
        print(f"{name:40s} {filepath}")

# WRONG: works on trees, hangs on graphs with cycles
def dfs_wrong(node, graph):
    for neighbour in graph[node]:
        dfs_wrong(neighbour, graph)

# RIGHT: track visited nodes
def dfs(node, graph, visited=None):
    if visited is None:
        visited = set()
    if node in visited:
        return
    visited.add(node)
    for neighbour in graph[node]:
        dfs(neighbour, graph, visited)

