# RIGHT: memoized — O(n) time
from functools import cache
@cache
def fib(n):
    if n < 2: return n
    return fib(n - 1) + fib(n - 2)

# WRONG: _result persists across top-level calls
def collect(node, _result=[]):
    _result.append(node.val)
    for child in node.children:
        collect(child, _result)
    return _result

# RIGHT: None sentinel, allocate fresh each time
def collect(node, _result=None):
    if _result is None:
        _result = []
    _result.append(node.val)
    for child in node.children:
        collect(child, _result)
    return _result

// Trampoline — avoids stack overflow for deep tail-recursive functions
function trampoline(fn) {
  return function(...args) {
    let result = fn(...args);
    while (typeof result === "function") {
      result = result();
    }
    return result;
  };
}

// Tail-recursive factorial using thunks (lazy calls)
function factTail(n, acc = 1) {
  if (n <= 1) return acc;
  return () => factTail(n - 1, n * acc);  // return thunk instead of calling directly
}

const factorial = trampoline(factTail);
console.log(factorial(100000));  // works without stack overflow
